// 比較 specificity：回傳 [id, class, element] 三元組，由左到右比大小
function specificity(sel) {
  const ids = (sel.match(/#[\w-]+/g) || []).length;
  const classes = (sel.match(/\.[\w-]+/g) || []).length;
  const elements = (sel.replace(/[#.][\w-]+/g, ' ')
                       .match(/[a-zA-Z][\w-]*/g) || []).length;
  return [ids, classes, elements];
}
const a = "#content";
const b = "div p.text.big";
console.log(a, "=>", specificity(a));   // id 選擇器
console.log(b, "=>", specificity(b));   // 兩個 class + 兩個 element
console.log("套用者:", specificity(a) > specificity(b) ? a : b);

// 三種來源套在同一段文字上的 color，數字越大優先
const inlineStyle = 1000;  // style="" 行內
const idRule      = 100;   // #para
const classRule   = 10;    // .para
const winner = Math.max(inlineStyle, idRule, classRule);
