// 解析一條 rule set，取出 selector 與各 declaration
const ruleSet = "h1.title { color: navy; font-size: 24px; }";
const selector = ruleSet.slice(0, ruleSet.indexOf("{")).trim();
const body = ruleSet.slice(ruleSet.indexOf("{") + 1, ruleSet.indexOf("}"));
const declarations = body.split(";")
  .map(d => d.trim())
  .filter(Boolean)
  .map(d => {
    const [prop, val] = d.split(":").map(s => s.trim());
    return { property: prop, value: val };
  });
console.log("selector:", selector);
console.log("declarations:", JSON.stringify(declarations));

// descendant selector "ul li a" 是否命中一條祖先鏈？
const chain = ["ul", "li", "span", "a"];   // a 在 ul 內、也在 li 內
const needed = ["ul", "li", "a"];          // 只要依序出現即可（不必相鄰）
let i = 0;
for (const node of chain) if (node === needed[i]) i++;
console.log("符合 'ul li a'?", i === needed.length);

